import 'package:flutter/material.dart'; import '../theme/app_theme.dart'; class GradientContainer extends StatelessWidget { final Widget child; final List<Color> colors; final double borderRadius; const GradientContainer({super.key, required this.child, this.colors = const [AppTheme.primaryColor, AppTheme.accentColor], this.borderRadius = 16}); @override Widget build(BuildContext context) => Container(decoration: BoxDecoration(gradient: LinearGradient(colors: colors, begin: Alignment.topLeft, end: Alignment.bottomRight), borderRadius: BorderRadius.circular(borderRadius)), child: child); }
